import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import ModalNuevaSucursal from './ModalNuevaSucursal';

const Dashboard = () => {
    const { user } = useAuth();
    const [locales, setLocales] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchLocales();
    }, [user.id]);

    const fetchLocales = async () => {
        try {
            const data = await api.getLocalesVendedor(user.id);
            setLocales(data);
        } catch (error) {
            console.error("Error cargando locales:", error);
        } finally {
            setLoading(false);
        }
    };

    const manejarNuevaSucursal = async (nuevaData) => {
        try {
            const creado = await api.crearLocal(nuevaData);
            setLocales([...locales, creado]);
        } catch (error) {
            alert("Error al crear sucursal");
        }
    };

    if (loading) return <div>Cargando tus comercios...</div>;

    return (
        <div style={{ padding: '20px' }}>
            <h1>Mis Locales</h1>
            <ModalNuevaSucursal onSave={manejarNuevaSucursal} />
            <div style={gridEstilo}>
                {locales.map(local => (
                    <div key={local._id} style={cardEstilo}>
                        <h3>{local.nombre}</h3>
                        <p>{local.direccion}</p>
                        <button onClick={() => window.location.href=`/ofertas/${local._id}`}>
                            Gestionar Ofertas
                        </button>
                    </div>
                ))}
            </div>
        </div>
    );
};

const gridEstilo = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' };
const cardEstilo = { border: '1px solid #ddd', padding: '15px', borderRadius: '8px' };

export default Dashboard;
